	Name             string              `json:"name"`
	EntryPoints      []SandboxEntryPoint `json:"entryPoints"`
	SessionID        string              `json:"sessionId"`
	CreatedAt        TimeWrapper         `json:"createdAt"`
	ExpiresAt        TimeWrapper         `json:"expiresAt"`
